This is an obfuscated implementation of the **A* (A-star) pathfinding algorithm** operating on a 2D grid. The code generates a grid with random obstacles, sets a start and end point, and attempts to find the shortest path between them using a defined heuristic (either Manhattan or Euclidean distance) and octile movement (horizontal, vertical, and diagonal).

Here is a clean, modern, and readable implementation of the exact same logic written from scratch:

```javascript
// --- Configuration ---
const gridWidth = 20;
const gridHeight = 15;
const config = {
    penalty: 'manhattan',   // Heuristic type
    adjacentCost: 1.414,    // Cost for diagonal movement (approx √2)
    traversalCost: 1,       // Cost for vertical/horizontal movement
    maxIterations: 1000,    // Safety limit to prevent infinite loops
    obstacleRatio: 0.25     // 25% chance for a cell to be a wall
};

// --- Grid Initialization ---
const grid = [];
for (let y = 0; y < gridHeight; y++) {
    grid[y] = [];
    for (let x = 0; x < gridWidth; x++) {
        // 1 = Obstacle, 0 = Walkable path
        grid[y][x] = Math.random() < config.obstacleRatio ? 1 : 0;
    }
}

// Define Start and Destination Nodes
const startNode = { x: 0, y: 0 };
const endNode = { x: gridWidth - 1, y: gridHeight - 1 };

// Ensure the start and end nodes are never blocked
grid[startNode.y][startNode.x] = 0;
grid[endNode.y][endNode.x] = 0;


// --- Helper Functions ---

/**
 * Calculates the heuristic (estimated distance) between two nodes.
 */
function getHeuristic(node1, node2) {
    const dx = Math.abs(node1.x - node2.x);
    const dy = Math.abs(node1.y - node2.y);

    if (config.penalty === 'manhattan') {
        return dx + dy;
    }
    return Math.sqrt(dx * dx + dy * dy); // Euclidean distance
}

/**
 * Retrieves valid adjacent walkable nodes for a given node.
 */
function getNeighbors(node) {
    const neighbors = [];
    const directions = [
        { dx: 0, dy: -1, cost: config.traversalCost }, // Up
        { dx: 0, dy: 1, cost: config.traversalCost },  // Down
        { dx: -1, dy: 0, cost: config.traversalCost }, // Left
        { dx: 1, dy: 0, cost: config.traversalCost },  // Right
        { dx: -1, dy: -1, cost: config.adjacentCost }, // Top-Left
        { dx: 1, dy: -1, cost: config.adjacentCost },  // Top-Right
        { dx: -1, dy: 1, cost: config.adjacentCost },  // Bottom-Left
        { dx: 1, dy: 1, cost: config.adjacentCost }    // Bottom-Right
    ];

    for (const dir of directions) {
        const nx = node.x + dir.dx;
        const ny = node.y + dir.dy;

        // Check bounds and if the node is walkable (0)
        if (nx >= 0 && nx < gridWidth && ny >= 0 && ny < gridHeight && grid[ny][nx] === 0) {
            neighbors.push({ x: nx, y: ny, moveCost: dir.cost });
        }
    }
    return neighbors;
}

/**
 * Creates a unique string identifier for tracking nodes in sets.
 */
function getNodeKey(node) {
    return `${node.x},${node.y}`;
}


// --- A* Pathfinding Algorithm ---

function findPath(start, end) {
    const openSet = {};
    const closedSet = {};
    const gScore = {}; // Cost from start to a node
    const fScore = {}; // Estimated total cost (gScore + heuristic)
    const cameFrom = {}; // For path reconstruction

    let iterations = 0;
    const startKey = getNodeKey(start);

    // Initialize starting values
    openSet[startKey] = start;
    gScore[startKey] = 0;
    fScore[startKey] = getHeuristic(start, end);

    // Loop until we evaluate all open nodes or hit the execution limit
    while (Object.keys(openSet).length > 0 && iterations < config.maxIterations) {
        iterations++;

        // 1. Find the node in openSet with the lowest fScore
        let currentKey = null;
        let minFScore = Infinity;

        for (const key in openSet) {
            if (fScore[key] < minFScore) {
                minFScore = fScore[key];
                currentKey = key;
            }
        }
        const current = openSet[currentKey];

        // 2. Check if we reached our destination
        if (current.x === end.x && current.y === end.y) {
            const path = [current];
            let currKey = currentKey;

            // Reconstruct path backward from target to start
            while (cameFrom[currKey]) {
                currKey = cameFrom[currKey];

                // Fetch the object, fallback to constructing it from its coordinate string key
                const parentNode = openSet[currKey] || closedSet[currKey] || { 
                    x: parseInt(currKey.split(',')[0]), 
                    y: parseInt(currKey.split(',')[1]) 
                };
                path.unshift(parentNode); // Prepends to the start of the array
            }
            return { path, cost: gScore[currentKey], iterations };
        }

        // 3. Move current node from openSet to closedSet
        delete openSet[currentKey];
        closedSet[currentKey] = current;

        // 4. Process all valid adjacent neighbors
        const neighbors = getNeighbors(current);

        for (const neighbor of neighbors) {
            const neighborKey = getNodeKey(neighbor);

            // Ignore nodes we have already fully evaluated
            if (closedSet[neighborKey]) continue;

            const tentativeGScore = gScore[currentKey] + neighbor.moveCost;

            // If we found a shorter path to this neighbor, record it
            if (gScore[neighborKey] === undefined || tentativeGScore < gScore[neighborKey]) {
                cameFrom[neighborKey] = currentKey;
                gScore[neighborKey] = tentativeGScore;
                fScore[neighborKey] = tentativeGScore + getHeuristic(neighbor, end);

                // Add to openSet to evaluate later
                openSet[neighborKey] = neighbor;
            }
        }
    }

    // No path could be found
    return { path: [], cost: Infinity, iterations };
}

// --- Execution ---
const result = findPath(startNode, endNode);

console.log(
    'Path length:', result.path.length,
    'Cost:', result.cost.toFixed(2), 
    'Iterations:', result.iterations
);
